/**
 * Sound bites played during the practice summary ring animation.
 *
 *   - ring-fill-good  : Mixkit 2633 ("Sweeping sparkle presentation"),
 *                       trimmed to 1.4s with 200ms fade-out. Used when
 *                       the run's accuracy is ≥80% (green ring).
 *   - ring-fill-bad   : Mixkit 255  ("Fantasy game sweep notification"),
 *                       trimmed to 1.4s with 200ms fade-out. Used when
 *                       accuracy is <80% (amber / red ring).
 *   - perfect         : Mixkit 523  ("Ethereal fairy win sound"). Drops
 *                       on top of the ring sound at t=1.2s when the user
 *                       hits a perfect score (score === total).
 *
 * Embedded as base64 so call sites can use Audio.Sound.createAsync({uri})
 * without going through expo-asset (which is brittle when the consuming
 * component lives at module top-level, outside a screen). Same pattern
 * as practiceSoundUris.ts for the per-question feedback sounds.
 */
export const PRACTICE_RING_FILL_GOOD_URI = "data:audio/mp3;base64,";
export const PRACTICE_RING_FILL_BAD_URI  = "data:audio/mp3;base64,";
export const PRACTICE_PERFECT_URI        = "data:audio/mp3;base64,";
